void SharedCountImpl::release() {
    auto uc = use_count.load(::std::memory_order_seq_cst) - 1;
    use_count.store(uc, ::std::memory_order_seq_cst);
    if (uc == 0) {
        // dispose / destroy are private vfuncs (no auto-generated public
        // wrappers); call through the vftable pointer directly.
        _vftable_ptr()->dispose(this);
        weak_release();
    }
}

void SharedCountImpl::weak_release() {
    auto wc = weak_count.load(::std::memory_order_seq_cst) - 1;
    weak_count.store(wc, ::std::memory_order_seq_cst);
    if (wc == 0) {
        _vftable_ptr()->destroy(this);
    }
}

void SharedCountImpl::add_ref_copy() {
    use_count.fetch_add(1, ::std::memory_order_seq_cst);
}

void SharedCountImpl::weak_add_ref() {
    weak_count.fetch_add(1, ::std::memory_order_seq_cst);
}

void SharedCount::release() {
