// JC2 ships against MSVCP80's `std::basic_string` ABI; we resolve the
// constructors / destructor / copy by mangled name from the loaded DLL on
// first use (mirrors the Rust impl). The mangled names target the 32-bit
// __thiscall variants from MSVCP80, which is what the game binary links
// against.
namespace {
    struct StdStringFunctions {
        void (PYXIS_THISCALL *ctor_default)(StdString*);
        void (PYXIS_THISCALL *ctor_cstr)(StdString*, const char*);
        void (PYXIS_THISCALL *dtor)(StdString*);
        void (PYXIS_THISCALL *copy)(StdString*, const StdString*);
    };

    const StdStringFunctions& std_string_functions() {
        static const StdStringFunctions fns = []() -> StdStringFunctions {
            HMODULE module = ::GetModuleHandleA("MSVCP80");
            auto resolve = [&](const char* mangled) -> FARPROC {
                return module ? ::GetProcAddress(module, mangled) : nullptr;
            };
            StdStringFunctions out{};
            out.ctor_default = reinterpret_cast<decltype(out.ctor_default)>(
                resolve("??0?$basic_string@DU?$char_traits@D@std@@V?$allocator@D@2@@std@@QAE@XZ"));
            out.ctor_cstr = reinterpret_cast<decltype(out.ctor_cstr)>(
                resolve("??0?$basic_string@DU?$char_traits@D@std@@V?$allocator@D@2@@std@@QAE@PBD@Z"));
            out.dtor = reinterpret_cast<decltype(out.dtor)>(
                resolve("??1?$basic_string@DU?$char_traits@D@std@@V?$allocator@D@2@@std@@QAE@XZ"));
            out.copy = reinterpret_cast<decltype(out.copy)>(
                resolve("??4?$basic_string@DU?$char_traits@D@std@@V?$allocator@D@2@@std@@QAEAAV01@ABV01@@Z"));
            return out;
        }();
        return fns;
    }
}

void StdString::ctor() { std_string_functions().ctor_default(this); }
void StdString::ctor_cstr(const char* s) { std_string_functions().ctor_cstr(this, s); }
void StdString::dtor() { std_string_functions().dtor(this); }
void StdString::copy(const StdString* other) { std_string_functions().copy(this, other); }

